//go:build ignore

// Package config loads the service configuration via koanf.
//
// Precedence (lowest → highest):
//  1. Defaults baked into the binary.
//  2. ./config.yaml shipped in the container image.
//  3. Path passed via CONFIG_FILE env var (optional).
//  4. OF_<KEY> environment variables (override at runtime).
//
// Mirrors the standard OpenFoundry Go service precedence so deployments
// can reuse the same Helm value templates.
package config

import (
	"fmt"
	"strings"

	"github.com/knadh/koanf/parsers/yaml"
	"github.com/knadh/koanf/providers/env"
	"github.com/knadh/koanf/providers/file"
	"github.com/knadh/koanf/v2"
)

// Config is the typed view of every knob the template exposes.
//
// Real services should extend this struct with their own fields and
// keep the YAML schema documented in the service README.
type Config struct {
	Service struct {
		Name    string `koanf:"name"`
		Version string `koanf:"version"`
	} `koanf:"service"`

	Server struct {
		Addr            string `koanf:"addr"`
		ShutdownTimeout string `koanf:"shutdown_timeout"`
	} `koanf:"server"`

	JWT struct {
		Secret   string `koanf:"secret"`
		Issuer   string `koanf:"issuer"`
		Audience string `koanf:"audience"`
	} `koanf:"jwt"`

	Telemetry struct {
		OTLPEndpoint string `koanf:"otlp_endpoint"`
		LogFormat    string `koanf:"log_format"`
	} `koanf:"telemetry"`
}

// Load resolves the configuration following the documented precedence.
//
// `defaultsPath` points at the YAML file shipped in the image (use
// "config.yaml" for the template). `envPath` is optional and overrides
// the in-image config when set (typically CONFIG_FILE).
func Load(defaultsPath, envPath string) (*Config, error) {
	k := koanf.New(".")

	if err := k.Load(file.Provider(defaultsPath), yaml.Parser()); err != nil {
		return nil, fmt.Errorf("load defaults from %s: %w", defaultsPath, err)
	}
	if envPath != "" {
		if err := k.Load(file.Provider(envPath), yaml.Parser()); err != nil {
			return nil, fmt.Errorf("load env config from %s: %w", envPath, err)
		}
	}
	// OF_SERVICE__NAME, OF_SERVER__ADDR, OF_JWT__SECRET …
	envProvider := env.Provider("OF_", ".", func(s string) string {
		return strings.ToLower(strings.ReplaceAll(strings.TrimPrefix(s, "OF_"), "__", "."))
	})
	if err := k.Load(envProvider, nil); err != nil {
		return nil, fmt.Errorf("load env overrides: %w", err)
	}

	var cfg Config
	if err := k.Unmarshal("", &cfg); err != nil {
		return nil, fmt.Errorf("unmarshal config: %w", err)
	}
	return &cfg, nil
}
